// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}





export default function Component(props: Props) {
  // Helper function to get weather emoji/icon based on condition
  const getWeatherIcon = (condition: string): string => {
    const lowerCondition = condition.toLowerCase();
    if (lowerCondition.includes('sunny') || lowerCondition.includes('clear')) return '☀️';
    if (lowerCondition.includes('cloudy') || lowerCondition.includes('cloud')) return '☁️';
    if (lowerCondition.includes('rainy') || lowerCondition.includes('rain')) return '🌧️';
    if (lowerCondition.includes('snow')) return '❄️';
    if (lowerCondition.includes('wind')) return '💨';
    if (lowerCondition.includes('fog') || lowerCondition.includes('mist')) return '🌫️';
    if (lowerCondition.includes('thunder') || lowerCondition.includes('storm')) return '⛈️';
    return '🌤️'; // default
  };

  return (
    <Container maxWidth="lg" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Main weather card */}
        <Card padding="var(--ggui-spacing-8)" shadow="md" radius="lg">
          <Stack gap="var(--ggui-spacing-6)">
            {/* City name */}
            <Heading level={1} color="var(--ggui-color-onSurface)">{props.city}</Heading>

            {/* Current temperature and condition section */}
            <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-6)">
              {/* Large temperature display */}
              <Box>
                <Text size="4xl" weight="bold" color="var(--ggui-color-primary-600)">
                  {props.temperature}°{props.unit}
                </Text>
              </Box>

              {/* Spacer to separate temp from condition */}
              <Divider orientation="vertical" margin="var(--ggui-spacing-4)" color="var(--ggui-color-outlineVariant)" />

              {/* Weather condition with icon */}
              <Stack gap="var(--ggui-spacing-2)" align="center">
                <Icon name={getWeatherIcon(props.condition)} size={64} />
                <Text variant="bodyLarge" color="var(--ggui-color-onSurface)" weight="semibold">
                  {props.condition}
                </Text>
              </Stack>
            </Stack>

            {/* Divider */}
            <Divider orientation="horizontal" margin="var(--ggui-spacing-4)" color="var(--ggui-color-outlineVariant)" />

            {/* Humidity and Wind Speed Row */}
            <Row gap="var(--ggui-spacing-6)" justify="start">
              {/* Humidity */}
              <Box>
                <Stack gap="var(--ggui-spacing-2)">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                    Humidity
                  </Text>
                  <Row gap="var(--ggui-spacing-2)" align="center">
                    <Icon name="droplet" size={20} color="var(--ggui-color-primary-600)" />
                    <Text size="lg" weight="semibold" color="var(--ggui-color-onSurface)">
                      {props.humidity}%
                    </Text>
                  </Row>
                </Stack>
              </Box>

              {/* Wind Speed */}
              <Box>
                <Stack gap="var(--ggui-spacing-2)">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                    Wind Speed
                  </Text>
                  <Row gap="var(--ggui-spacing-2)" align="center">
                    <Icon name="wind" size={20} color="var(--ggui-color-primary-600)" />
                    <Text size="lg" weight="semibold" color="var(--ggui-color-onSurface)">
                      {props.windSpeed} km/h
                    </Text>
                  </Row>
                </Stack>
              </Box>
            </Row>
          </Stack>
        </Card>

        {/* 5-Day Forecast Section */}
        <Stack gap="var(--ggui-spacing-4)">
          <Heading level={3} color="var(--ggui-color-onSurface)">
            5-Day Forecast
          </Heading>

          {/* Forecast strip */}
          <Row gap="var(--ggui-spacing-3)" justify="start" wrap>
            {props.forecast && props.forecast.length > 0 ? (
              props.forecast.map((day, index) => (
                <Card key={index} padding="var(--ggui-spacing-4)" shadow="sm" radius="md" style={{ flex: '0 1 auto', minWidth: '120px' }}>
                  <Stack gap="var(--ggui-spacing-3)" align="center">
                    {/* Day name */}
                    <Text variant="label" weight="semibold" color="var(--ggui-color-onSurface)">
                      {day.day || `Day ${index + 1}`}
                    </Text>

                    {/* Weather icon */}
                    <Icon name={day.icon || '🌤️'} size={40} />

                    {/* High/Low temps */}
                    <Stack gap="var(--ggui-spacing-1)" align="center">
                      <Text size="sm" weight="semibold" color="var(--ggui-color-onSurface)">
                        {day.high}°
                      </Text>
                      <Text size="sm" color="var(--ggui-color-onSurfaceVariant)">
                        {day.low}°
                      </Text>
                    </Stack>
                  </Stack>
                </Card>
              ))
            ) : (
              <Text color="var(--ggui-color-onSurfaceVariant)" variant="bodySmall">
                No forecast data available
              </Text>
            )}
          </Row>
        </Stack>
      </Stack>
    </Container>
  );
}

