import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

  // State for multi-step form
  const [currentStep, setCurrentStep] = useState(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');

  // Validation helper
  const isValidEmail = (value: string): boolean => {
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value);
  };

  // Validation state for Step 1
  const nameError = name.trim() === '' ? 'Name is required' : '';
  const emailError = email.trim() === '' ? 'Email is required' : !isValidEmail(email) ? 'Please enter a valid email address' : '';
  const step1Valid = name.trim() !== '' && email.trim() !== '' && isValidEmail(email);

  // Validation for Step 2
  const step2Valid = satisfaction !== '';

  // Handle next button
  const handleNext = () => {
    if (currentStep === 1 && !step1Valid) return;
    if (currentStep === 2 && !step2Valid) return;
    if (currentStep < 4) {
      setCurrentStep(currentStep + 1);
    }
  };
  // Handle back button
  const handleBack = () => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  };

  // Handle feature checkbox toggle
  const handleFeatureToggle = (feature: string) => {
    setFeatures((prev) =>
      prev.includes(feature) ? prev.filter((f) => f !== feature) : [...prev, feature]
    );
  };

  // Handle form submission
  const handleSubmit = () => {
    submit({
      name,
      email,
      satisfaction: parseInt(satisfaction, 10),
      features,
      comments,
    });
  };

  // Generate satisfaction radio options from props
  const satisfactionOptions = props.satisfactionLabels.map((label, index) => ({
    value: String(index + 1),
    label: `${index + 1} - ${label}`,
  }));

  return (
    <Container maxWidth="lg" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Box>
          <Heading level={1}>Customer Survey</Heading>
          <Divider margin="var(--ggui-spacing-2)" />
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)" style={{ marginTop: 'var(--ggui-spacing-2)' }}>
            Step {currentStep} of 4
          </Text>
        </Box>

        {/* Progress Bar */}
        <Progress value={currentStep} max={4} size="md" variant="default" />

        {/* Step 1: Name and Email */}
        {currentStep === 1 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={2}>Your Information</Heading>
              <Input
                label="Full Name"
                placeholder="John Doe"
                value={name}
                onChange={setName}
                error={nameError}
                required
              />
              <Input
                label="Email Address"
                type="email"
                placeholder="john@example.com"
                value={email}
                onChange={setEmail}
                error={emailError}
                required
              />
            </Stack>
          </Card>
        )}

        {/* Step 2: Satisfaction Rating */}
        {currentStep === 2 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={2}>Satisfaction Rating</Heading>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                How satisfied are you with our service?
              </Text>
              <RadioGroup
                label="Rate your satisfaction"
                value={satisfaction}
                onChange={setSatisfaction}
                options={satisfactionOptions}
                direction="vertical"
              />
            </Stack>
          </Card>
        )}

        {/* Step 3: Feature Interests */}
        {currentStep === 3 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={2}>Features of Interest</Heading>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                Which features are you most interested in? (Select all that apply)
              </Text>
              <Stack gap="var(--ggui-spacing-3)">
                {props.featureOptions.map((feature) => (
                  <Checkbox
                    key={feature}
                    label={feature}
                    checked={features.includes(feature)}
                    onChange={() => handleFeatureToggle(feature)}
                  />
                ))}
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Step 4: Comments */}
        {currentStep === 4 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={2}>Additional Comments</Heading>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                Please share any additional feedback or suggestions (optional)
              </Text>
              <TextArea
                label="Comments"
                placeholder="Tell us what you think..."
                value={comments}
                onChange={setComments}
                maxLength={500}
                showCount
                rows={6}
              />
            </Stack>
          </Card>
        )}

        {/* Step 5: Review */}
        {currentStep === 5 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={2}>Review Your Answers</Heading>
              <Stack gap="var(--ggui-spacing-2)">
                {[
                  { label: 'Name', value: name },
                  { label: 'Email', value: email },
                   { label: 'Satisfaction Rating', value: satisfaction && props.satisfactionLabels && parseInt(satisfaction, 10) > 0 && parseInt(satisfaction, 10) <= props.satisfactionLabels.length ? `${satisfaction} - ${props.satisfactionLabels[parseInt(satisfaction, 10) - 1]}` : '(Not answered)' },
                  { label: 'Features of Interest', value: features.length > 0 ? features.join(', ') : 'None selected' },
                  { label: 'Comments', value: comments || '(No comments provided)' },
                ].map((item) => (
                  <Box key={item.label} padding="var(--ggui-spacing-3)" background="var(--ggui-color-surfaceVariant)" borderRadius="var(--ggui-shape-radius-md)">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">{item.label}</Text>
                    <Text variant="body">{item.value}</Text>
                  </Box>
                ))}
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Navigation Buttons */}
        <Divider margin="var(--ggui-spacing-4)" />
        <Row gap="var(--ggui-spacing-3)" justify="end">
          {currentStep > 1 && (
            <Button variant="ghost" onClick={handleBack}>
              Back
            </Button>
          )}
          {currentStep < 5 && (
            <Button
              variant="primary"
              onClick={handleNext}
              disabled={
                (currentStep === 1 && !step1Valid) ||
                (currentStep === 2 && !step2Valid)
              }
            >
              Next
            </Button>
          )}
          {currentStep === 5 && (
            <Button variant="primary" onClick={handleSubmit}>
              Submit
            </Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}

