  elements: Array<{ atomicNumber?: number; symbol?: string; name?: string; atomicWeight?: number; category?: string; row?: number; col?: number }>; // Full periodic table element data
}





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  // State for search filtering
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<typeof props.elements[0] | null>(null);

  // Filter elements by search query (name or symbol, case-insensitive)
  const filteredElements = useMemo(() => {
    if (!searchQuery.trim()) return props.elements;
    const query = searchQuery.toLowerCase();
    return props.elements.filter(el =>
      (el.name?.toLowerCase().includes(query) || el.symbol?.toLowerCase().includes(query))
    );
  }, [searchQuery, props.elements]);

  // Get unique categories for legend
  const categories = useMemo(() => {
    const cats = new Set(props.elements.map(el => el.category).filter(Boolean));
    return Array.from(cats).sort();
  }, [props.elements]);

  // Map category to color token
  const getCategoryColor = (category: string | undefined): string => {
    if (!category) return 'var(--ggui-color-surfaceVariant)';
    const colorMap: Record<string, string> = {
      'noble-gas': 'var(--ggui-color-info-100)',
      'halogen': 'var(--ggui-color-warning-100)',
      'alkaline-earth-metal': 'var(--ggui-color-success-100)',
      'transition-metal': 'var(--ggui-color-primary-100)',
      'alkali-metal': 'var(--ggui-color-error-100)',
      'lanthanide': 'var(--ggui-color-primary-50)',
      'actinide': 'var(--ggui-color-warning-50)',
      'metalloid': 'var(--ggui-color-secondary-100)',
      'nonmetal': 'var(--ggui-color-success-50)',
      'metal': 'var(--ggui-color-neutral-100)',
    };
    return colorMap[category] || 'var(--ggui-color-surfaceVariant)';
  };

  // Get category text color
  const getCategoryTextColor = (category: string | undefined): string => {
    if (!category) return 'var(--ggui-color-onSurface)';
    const colorMap: Record<string, string> = {
      'noble-gas': 'var(--ggui-color-info-700)',
      'halogen': 'var(--ggui-color-warning-700)',
      'alkaline-earth-metal': 'var(--ggui-color-success-700)',
      'transition-metal': 'var(--ggui-color-primary-700)',
      'alkali-metal': 'var(--ggui-color-error-700)',
      'lanthanide': 'var(--ggui-color-primary-700)',
      'actinide': 'var(--ggui-color-warning-700)',
      'metalloid': 'var(--ggui-color-secondary-700)',
      'nonmetal': 'var(--ggui-color-success-700)',
      'metal': 'var(--ggui-color-neutral-700)',
    };
    return colorMap[category] || 'var(--ggui-color-onSurface)';
  };

  return (
    <Container maxWidth="100%" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Header with title */}
        <Stack gap="var(--ggui-spacing-2)">
          <Heading level={1}>Periodic Table of Elements</Heading>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
            Click on any element to view details
          </Text>
        </Stack>

        {/* Search input */}
        <SearchField
          value={searchQuery}
          onChange={setSearchQuery}
           placeholder="Search by name or symbol..."
          onSearch={() => {}}
        />

        {/* Legend */}
        <Card padding="var(--ggui-spacing-4)" shadow="sm">
          <Stack gap="var(--ggui-spacing-3)">
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Category Legend</Text>
            <Row gap="var(--ggui-spacing-3)" wrap={true}>
              {categories.map(cat => (
                <Row key={cat} gap="var(--ggui-spacing-2)" align="center">
                  <Box
                    background={getCategoryColor(cat)}
                    borderRadius="var(--ggui-shape-radius-sm)"
                    padding="var(--ggui-spacing-1)"
                    style={{ width: '16px', height: '16px' }}
                  />
                  <Text variant="caption" color="var(--ggui-color-onSurface)">{cat}</Text>
                </Row>
              ))}
            </Row>
          </Stack>
        </Card>

        {/* Periodic Table Grid */}
        <Box
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, 1fr)',
            gap: 'var(--ggui-spacing-2)',
            padding: 'var(--ggui-spacing-4)',
            background: 'var(--ggui-color-surface)',
            borderRadius: 'var(--ggui-shape-radius-lg)',
            border: '1px solid var(--ggui-color-outline)',
          }}
        >
          {filteredElements.map((element) => (
            <Card
              key={element.symbol || element.atomicNumber}
              as={Clickable}
              onClick={() => setSelectedElement(element)}
              shadow="sm"
              padding="var(--ggui-spacing-2)"
              radius="md"
              style={{
                gridRow: element.row,
                gridColumn: element.col,
                background: getCategoryColor(element.category),
                cursor: 'pointer',
                transition: 'all 200ms ease-in-out',
              }}
              className={selectedElement?.symbol === element.symbol ? 'selected' : ''}
            >
              <Stack gap="var(--ggui-spacing-1)" align="center" justify="center">
                <Text
                  variant="caption"
                  color={getCategoryTextColor(element.category)}
                  align="center"
                  style={{ fontSize: 'var(--ggui-font-size-xs)' }}
                >
                  {element.atomicNumber}
                </Text>
                <Text
                  variant="label"
                  color={getCategoryTextColor(element.category)}
                  align="center"
                  weight="bold"
                  style={{ fontSize: 'var(--ggui-font-size-lg)' }}
                >
                  {element.symbol}
                </Text>
              </Stack>
            </Card>
          ))}
        </Box>

        {/* Detail Panel */}
        {selectedElement && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Row gap="var(--ggui-spacing-3)" align="center" justify="between">
                <Heading level={2}>{selectedElement.name}</Heading>
                <Button
                  variant="ghost"
                  size="sm"
                  onClick={() => setSelectedElement(null)}
                >
                  Close
                </Button>
              </Row>

              <Divider />

              <Row gap="var(--ggui-spacing-6)" justify="start">
                <Box>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Symbol</Text>
                  <Text variant="body" weight="bold" color="var(--ggui-color-onSurface)">{selectedElement.symbol}</Text>
                </Box>

                <Box>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Atomic Number</Text>
                  <Text variant="body" weight="bold" color="var(--ggui-color-onSurface)">{selectedElement.atomicNumber}</Text>
                </Box>

                {selectedElement.atomicWeight !== undefined && (
                  <Box>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Atomic Weight</Text>
                    <Text variant="body" weight="bold" color="var(--ggui-color-onSurface)">{selectedElement.atomicWeight.toFixed(2)}</Text>
                  </Box>
                )}

                {selectedElement.category && (
                  <Box>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Category</Text>
                    <Badge
                      variant="primary"
                      size="md"
                    >
                      {selectedElement.category}
                    </Badge>
                  </Box>
                )}
              </Row>
            </Stack>
          </Card>
        )}

        {/* Empty state */}
        {filteredElements.length === 0 && (
          <Alert variant="info" title="No Results">
            No elements match your search query.
          </Alert>
        )}
      </Stack>
    </Container>
  );
}

