import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  product: { id?: string; name?: string; price?: number; currency?: string; rating?: number; reviewCount?: number; stock?: number; description?: string; specifications?: unknown[]; reviews?: unknown[] }; // Product object with id, name, price, currency, rating, stock, description, specifications[], reviews[]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user clicks Add to Cart. Payload: { productId, quantity } */
type ActionAddToCartPayload = { productId: string; quantity: number };





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const addToCart = useAction<ActionAddToCartPayload>('addToCart'); // Called when user clicks Add to Cart. Payload: { productId, quantity }

  // State for quantity selector
  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');

  // Compute derived values
  const maxStock = props.product.stock ?? 0;
  const isOutOfStock = maxStock === 0;
  const isLowStock = maxStock > 0 && maxStock <= 5;
  const productId = props.product.id ?? '';
  const ratingStars = Math.min(5, Math.max(1, Math.round(props.product.rating ?? 0)));
  const formattedPrice = props.product.currency && props.product.price ? `${props.product.currency}${props.product.price.toFixed(2)}` : `$${(props.product.price ?? 0).toFixed(2)}`;

  // Handlers
  const handleQuantityChange = useCallback((newValue: number) => {
    const clamped = Math.min(Math.max(1, newValue), maxStock);
    setQuantity(clamped);
  }, [maxStock]);

  const handleAddToCart = useCallback(() => {
    if (!isOutOfStock && productId) {
      addToCart({ productId, quantity });
    }
  }, [isOutOfStock, productId, quantity, addToCart]);

  // Ensure quantity is valid when stock changes
  useEffect(() => {
    if (quantity > maxStock) {
      setQuantity(Math.max(1, maxStock));
    }
  }, [maxStock, quantity]);

  // Helper: render star rating
  const StarRating = ({ rating }: { rating: number }) => {
    return (
      <Row gap="var(--ggui-spacing-1)" align="center">
        {Array.from({ length: 5 }).map((_, i) => (
          <Icon
            key={i}
            name="star"
            size={16}
            color={i < rating ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-outlineVariant)'}
          />
        ))}
        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
          {props.product.rating ?? 0} ({props.product.reviewCount ?? 0} reviews)
        </Text>
      </Row>
    );
  };

  // Helper: render specifications table
  const renderSpecifications = () => {
    if (!props.product.specifications || props.product.specifications.length === 0) {
      return <Text color="var(--ggui-color-onSurfaceVariant)">No specifications available.</Text>;
    }
    const specs = props.product.specifications as Array<{ key?: string; value?: string }>;
    return (
      <Table
        columns={[
          { key: 'key', header: 'Specification', width: '40%' },
          { key: 'value', header: 'Value', width: '60%' },
        ]}
        data={specs.map((s, idx) => ({ id: String(idx), key: s.key ?? '', value: s.value ?? '' }))}
        compact
        bordered={false}
      />
    );
  };

  // Helper: render reviews list
  const renderReviews = () => {
    if (!props.product.reviews || props.product.reviews.length === 0) {
      return <Text color="var(--ggui-color-onSurfaceVariant)">No reviews yet.</Text>;
    }
    const reviews = props.product.reviews as Array<{ author?: string; rating?: number; text?: string; date?: string }>;
    return (
      <Stack gap="var(--ggui-spacing-4)">
        {reviews.map((review, idx) => (
          <Card key={idx} padding="var(--ggui-spacing-4)" shadow="sm">
            <Stack gap="var(--ggui-spacing-2)">
              <Row gap="var(--ggui-spacing-3)" align="center">
                <Text variant="label" weight="semibold">
                  {review.author ?? 'Anonymous'}
                </Text>
                <StarRating rating={Math.round(review.rating ?? 0)} />
              </Row>
              <Text variant="body">{review.text ?? ''}</Text>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                {review.date ?? 'No date'}
              </Text>
            </Stack>
          </Card>
        ))}
      </Stack>
    );
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)">
        {/* TOP SECTION: Image, Title, Price, Rating, Stock */}
        <Stack direction="horizontal" gap="var(--ggui-spacing-6)" align="start" wrap>
          {/* Product Image Placeholder */}
          <Box
            background="var(--ggui-color-primary-100)"
            borderRadius="var(--ggui-shape-radius-lg)"
            padding="var(--ggui-spacing-8)"
            style={{ minWidth: '300px', maxWidth: '400px', aspectRatio: '1' }}
          >
            <Stack align="center" justify="center" style={{ height: '100%' }}>
              <Icon name="image" size={64} color="var(--ggui-color-primary-600)" />
              <Text variant="label" color="var(--ggui-color-primary-700)" align="center">
                {props.product.name ?? 'Product Image'}
              </Text>
            </Stack>
          </Box>

          {/* Product Details */}
          <Stack gap="var(--ggui-spacing-4)" style={{ flex: 1, minWidth: '300px' }}>
            <Stack gap="var(--ggui-spacing-2)">
              <Heading level={2}>{props.product.name ?? 'Product'}</Heading>
              <Heading level={3} color="var(--ggui-color-primary-600)">
                {formattedPrice}
              </Heading>
              <StarRating rating={ratingStars} />
            </Stack>

            {/* Stock Status Badge */}
            {isOutOfStock ? (
              <Badge variant="error" size="md">
                Out of Stock
              </Badge>
            ) : isLowStock ? (
              <Badge variant="warning" size="md">
                Low Stock ({maxStock} left)
              </Badge>
            ) : (
              <Badge variant="success" size="md">
                In Stock
              </Badge>
            )}
          </Stack>
        </Stack>

        {/* MIDDLE SECTION: Tab Navigation */}
        <Stack gap="var(--ggui-spacing-4)">
          <Tabs
            variant="line"
            size="md"
            items={[
              {
                key: 'description',
                label: 'Description',
                content: (
                  <Stack gap="var(--ggui-spacing-3)" style={{ paddingTop: 'var(--ggui-spacing-4)', paddingBottom: 'var(--ggui-spacing-4)' }}>
                    <Text variant="body">{props.product.description ?? 'No description available.'}</Text>
                  </Stack>
                ),
              },
              {
                key: 'specifications',
                label: 'Specifications',
                content: (
                  <Box style={{ paddingTop: 'var(--ggui-spacing-4)', paddingBottom: 'var(--ggui-spacing-4)' }}>{renderSpecifications()}</Box>
                ),
              },
              {
                key: 'reviews',
                label: 'Reviews',
                content: (
                  <Box style={{ paddingTop: 'var(--ggui-spacing-4)', paddingBottom: 'var(--ggui-spacing-4)' }}>{renderReviews()}</Box>
                ),
              },
            ]}
            activeKey={activeTab}
            onChange={setActiveTab}
          />
        </Stack>

        {/* BOTTOM SECTION: Quantity & Add to Cart */}
        <Stack gap="var(--ggui-spacing-4)" direction="horizontal" align="center">
          {/* Quantity Selector */}
          <Stack gap="var(--ggui-spacing-2)" direction="horizontal" align="center">
            <Text variant="label">Quantity:</Text>
            <Button
              variant="outline"
              size="sm"
              onClick={() => handleQuantityChange(quantity - 1)}
              disabled={quantity <= 1}
            >
              −
            </Button>
            <Input
              label=""
              type="number"
              value={String(quantity)}
              onChange={(val) => handleQuantityChange(parseInt(val, 10) || 1)}
              style={{ width: '60px', textAlign: 'center' }}
            />
            <Button
              variant="outline"
              size="sm"
              onClick={() => handleQuantityChange(quantity + 1)}
              disabled={quantity >= maxStock}
            >
              +
            </Button>
          </Stack>

          <Spacer size="flex" />

          {/* Add to Cart Button */}
          <Button
            variant="primary"
            size="lg"
            onClick={handleAddToCart}
            disabled={isOutOfStock}
          >
            {isOutOfStock ? 'Out of Stock' : 'Add to Cart'}
          </Button>
        </Stack>
      </Stack>
    </Container>
  );
}

