// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  title: string; // Chat window title
  currentUser: string; // Current user name (for right-aligning own messages)
  participantCount: number; // Number of participants
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>; // Initial messages to display on mount
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user sends a message. Payload: { text, timestamp } */
type ActionSendMessagePayload = { text: string; timestamp: string };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: New message from another participant — append to message list */
type StreamMessage = { sender?: string; text?: string; timestamp?: string };

/** Stream event: Typing indicator — show/hide based on active flag */
type StreamTyping = { sender?: string; active?: boolean };




export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const messageStream = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typingStream = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  // State for managing messages and typing indicators
  const [messages, setMessages] = useState(props.messages || []);
  const [typingUsers, setTypingUsers] = useState<{ [key: string]: boolean }>({});
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const [inputValue, setInputValue] = useState('');

  // Append new messages from stream
  useEffect(() => {
    if (messageStream.latest) {
      setMessages(prev => [...prev, messageStream.latest!]);
    }
  }, [messageStream.latest]);

  // Handle typing indicator updates
  useEffect(() => {
    if (typingStream.latest) {
      const { sender, active } = typingStream.latest;
      setTypingUsers(prev => {
        const updated = { ...prev };
        if (active && sender) {
          updated[sender] = true;
        } else if (sender) {
          delete updated[sender];
        }
        return updated;
      });
    }
  }, [typingStream.latest]);

  // Auto-scroll to bottom when new messages arrive
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  // Handle send message
  const handleSendMessage = useCallback(() => {
    if (inputValue.trim()) {
      sendMessage({ text: inputValue, timestamp: new Date().toISOString() });
      setInputValue('');
    }
  }, [inputValue, sendMessage]);

  // Handle Enter key in input
  const handleKeyDown = useCallback((e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  }, [handleSendMessage]);

  // Group consecutive messages from same sender
  const groupedMessages = useMemo(() => {
    const groups: Array<{ sender?: string; messages: Array<{ sender?: string; text?: string; timestamp?: string }> }> = [];
    messages.forEach(msg => {
      if (groups.length > 0 && groups[groups.length - 1].sender === msg.sender) {
        groups[groups.length - 1].messages.push(msg);
      } else {
        groups.push({ sender: msg.sender, messages: [msg] });
      }
    });
    return groups;
  }, [messages]);

  const typingIndicatorActive = Object.keys(typingUsers).length > 0;
  const typingUsersList = Object.keys(typingUsers);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-4)" style={{ height: '100vh', display: 'flex', flexDirection: 'column' }}>
        {/* Header */}
        <Card padding="var(--ggui-spacing-4)" shadow="sm">
          <Stack direction="horizontal" align="center" justify="between">
            <Heading level={3}>{props.title}</Heading>
            <Row gap="var(--ggui-spacing-4)" align="center">
              <Badge variant="primary">{props.participantCount} participants</Badge>
              {typingIndicatorActive && (
                <Row gap="var(--ggui-spacing-1)" align="center">
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                    {typingUsersList.join(', ')} typing
                  </Text>
                  <Spinner size={16} color="var(--ggui-color-onSurfaceVariant)" />
                </Row>
              )}
            </Row>
          </Stack>
        </Card>

        {/* Messages Area */}
        <Card
          padding="var(--ggui-spacing-4)"
          shadow="sm"
          style={{
            flex: 1,
            overflowY: 'auto',
            display: 'flex',
            flexDirection: 'column',
            gap: 'var(--ggui-spacing-3)',
          }}
        >
          {groupedMessages.map((group, groupIdx) => (
            <Stack key={`group-${groupIdx}`} gap="var(--ggui-spacing-2)">
              {group.messages.map((msg, msgIdx) => {
                const isCurrentUser = msg.sender === props.currentUser;
                return (
                  <Box
                    key={`msg-${groupIdx}-${msgIdx}`}
                    style={{
                      display: 'flex',
                      justifyContent: isCurrentUser ? 'flex-end' : 'flex-start',
                      marginBottom: msgIdx === group.messages.length - 1 ? 'var(--ggui-spacing-1)' : '0',
                    }}
                  >
                    <Card
                      padding="var(--ggui-spacing-3)"
                      shadow="none"
                      border={false}
                      style={{
                        maxWidth: '60%',
                        background: isCurrentUser
                          ? 'var(--ggui-color-primary-600)'
                          : 'var(--ggui-color-surfaceVariant)',
                        borderRadius: 'var(--ggui-shape-radius-lg)',
                      }}
                    >
                      {msgIdx === 0 && (
                        <Text variant="label" color={isCurrentUser ? 'white' : 'var(--ggui-color-onSurfaceVariant)'}>
                          {msg.sender}
                        </Text>
                      )}
                      <Text
                        variant="body"
                        color={isCurrentUser ? 'white' : 'var(--ggui-color-onSurface)'}
                        style={{ marginTop: msgIdx === 0 ? 'var(--ggui-spacing-1)' : '0' }}
                      >
                        {msg.text}
                      </Text>
                      <Text
                        variant="caption"
                        color={isCurrentUser ? 'rgba(255, 255, 255, 0.7)' : 'var(--ggui-color-onSurfaceVariant)'}
                        style={{ marginTop: 'var(--ggui-spacing-1)', fontSize: 'var(--ggui-font-size-xs)' }}
                      >
                        {msg.timestamp ? new Date(msg.timestamp).toLocaleTimeString() : ''}
                      </Text>
                    </Card>
                  </Box>
                );
              })}
            </Stack>
          ))}
          <div ref={messagesEndRef} />
        </Card>

        {/* Input Area */}
        <Row gap="var(--ggui-spacing-2)" align="center">
          <Input
            label=""
            placeholder="Type a message..."
            value={inputValue}
            onChange={setInputValue}
            onKeyDown={handleKeyDown}
            style={{ flex: 1 }}
          />
          <Button
            variant="primary"
            disabled={!inputValue.trim()}
            onClick={handleSendMessage}
          >
            Send
          </Button>
        </Row>
      </Stack>
    </Container>
  );
}

