/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };




export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update

  // State for displayed stocks (merged with live updates)
  const [displayStocks, setDisplayStocks] = useState(props.stocks || []);
  const [lastUpdatedTime, setLastUpdatedTime] = useState<Date | null>(null);
  const [selectedStock, setSelectedStock] = useState<string | null>(null);
  const [animatedSymbols, setAnimatedSymbols] = useState<Set<string>>(new Set());
  const updateTimeoutRef = useRef<NodeJS.Timeout | null>(null);

  // Merge live price updates into displayed stocks
  // Merge live price updates into displayed stocks
  useEffect(() => {
    if (priceUpdate.latest) {
      setDisplayStocks((prev) => {
        const updated = [...prev];
        const index = updated.findIndex((s) => s.symbol === priceUpdate.latest?.symbol);
        if (index >= 0) {
          updated[index] = {
            ...updated[index],
            price: priceUpdate.latest.price !== undefined ? priceUpdate.latest.price : updated[index].price,
            change: priceUpdate.latest.change !== undefined ? priceUpdate.latest.change : updated[index].change,
            changePercent: priceUpdate.latest.changePercent !== undefined ? priceUpdate.latest.changePercent : updated[index].changePercent,
          };
          // Trigger animation on price update
          setAnimatedSymbols((prev) => new Set(prev).add(priceUpdate.latest!.symbol!));
        }
        return updated;
      });
      setLastUpdatedTime(new Date());
    }
  }, [priceUpdate.latest]);

  // Update last updated time every second while component is mounted
  useEffect(() => {
    const interval = setInterval(() => {
      if (lastUpdatedTime) {
        // Trigger re-render to update 'Last Updated' text
        setLastUpdatedTime(new Date(lastUpdatedTime));
      }
    }, 1000);
    return () => clearInterval(interval);
  }, [lastUpdatedTime]);

  // Helper: format time elapsed since last update
  const getTimeElapsed = (date: Date | null): string => {
    if (!date) return 'Never';
    const now = new Date();
    const seconds = Math.floor((now.getTime() - date.getTime()) / 1000);
    if (seconds < 60) return `${seconds}s ago`;
    const minutes = Math.floor(seconds / 60);
    if (minutes < 60) return `${minutes}m ago`;
    const hours = Math.floor(minutes / 60);
    return `${hours}h ago`;
  };

  // Helper: determine if change is positive
  const isPositive = (change: number | undefined): boolean => {
    return change !== undefined && change > 0;
  };

  // Helper: get arrow icon for change
  const getChangeArrow = (change: number | undefined): string => {
    if (change === undefined) return '';
    return change > 0 ? '▲' : '▼';
  };

  // Helper: format price to 2 decimals
  const formatPrice = (price: number | undefined): string => {
    if (price === undefined) return 'N/A';
    return price.toFixed(2);
  };

  return (
    <>
      <MotionKeyframes />
      <Container maxWidth="2xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Header with title and last updated */}
