          <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
              Last Updated: {getTimeElapsed(lastUpdatedTime)}
            </Text>
          </Stack>
        </Row>

        {/* Market Status Badge */}
         {/* Market Status Badge */}
         {marketStatus.latest && (
           <Box padding="var(--ggui-spacing-3)" background="var(--ggui-color-primary-50)" borderRadius="var(--ggui-shape-radius-md)" role="status" aria-label="Market status">
             <Text variant="bodySmall" color="var(--ggui-color-primary-700)">
               Market Status: <strong>{marketStatus.latest.status || 'Unknown'}</strong>
               {marketStatus.latest.timestamp && <> — <time dateTime={new Date(marketStatus.latest.timestamp).toISOString()}>{new Date(marketStatus.latest.timestamp).toLocaleTimeString()}</time></>}
             </Text>
           </Box>
         )}

        {/* Stock Cards Grid */}
        {/* Stock Cards Grid */}
        <CardGrid columns={{ sm: 1, md: 3 }} gap="var(--ggui-spacing-4)">
          {displayStocks.length > 0 ? (
            displayStocks.map((stock) => {
              const positive = isPositive(stock.change);
              const changeColor = positive ? 'var(--ggui-color-success-600)' : 'var(--ggui-color-error-600)';
              const changeBg = positive ? 'var(--ggui-color-success-50)' : 'var(--ggui-color-error-50)';
              const changeBorder = positive ? 'var(--ggui-color-success-200)' : 'var(--ggui-color-error-200)';
              return (
                <Card
                  key={stock.symbol || 'unknown'}
                  shadow="md"
                  padding="var(--ggui-spacing-4)"
                  border={true}
                  radius="lg"
                  aria-label={`${stock.symbol || 'Unknown'} stock card, price ${formatPrice(stock.price)}, change ${stock.change?.toFixed(2) || 'N/A'}`}
                  style={{
                    borderColor: changeBorder,
                    borderWidth: '1px',
                    cursor: 'pointer',
                    transition: 'all 0.3s ease',
                  } as React.CSSProperties}
                >
                  <Stack gap="var(--ggui-spacing-3)">
                    {/* Ticker Symbol - Large and Bold */}
                    <Text
                      variant="body"
                      weight="bold"
                      size="2xl"
                      color="var(--ggui-color-onSurface)"
                    >
                      {stock.symbol || 'N/A'}
                    </Text>

                    {/* Company Name */}
                    <Text
                      variant="bodySmall"
                      color="var(--ggui-color-onSurfaceVariant)"
                    >
                      {stock.name || 'Unknown'}
                    </Text>

                    <Divider margin="var(--ggui-spacing-2)" />

                    {/* Current Price */}
                    <Stack gap="var(--ggui-spacing-1)" aria-label="Stock price">
                      <Text
