                        color="var(--ggui-color-onSurface)"
                        style={animatedSymbols.has(stock.symbol || '') ? {
                          animation: animation.flash,
                          '--ggui-flash-color': positive ? 'var(--ggui-color-success-100)' : 'var(--ggui-color-error-100)',
                        } as React.CSSProperties : undefined}
                      >
                        ${formatPrice(stock.price)}
                      </Text>
                    </Stack>

                    {/* Change Amount and Percentage */}
                    <Box
                      padding="var(--ggui-spacing-3)"
