// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };



export default function Component(props: Props) {
  // Actions — fire-and-forget to agent
  const complete = useAction<ActionCompletePayload>('complete');

  // State management
  const [currentStep, setCurrentStep] = useState<1 | 2 | 3>(1);
  const [formData, setFormData] = useState({
    name: props.initialProfile.name || '',
    email: props.initialProfile.email || '',
    avatar: props.initialProfile.avatar || (props.avatarOptions[0] || ''),
    role: props.initialProfile.role || '',
    emailNotifications: props.initialProfile.emailNotifications ?? true,
    theme: props.initialProfile.theme || 'light',
  });

  const [errors, setErrors] = useState<{ [key: string]: string }>({});

  // Validation helpers
  const validateEmail = (email: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(email);
  };

  const validateStep1 = (): boolean => {
    const newErrors: { [key: string]: string } = {};
    if (!formData.name.trim()) newErrors.name = 'Name is required';
    if (!formData.email.trim()) newErrors.email = 'Email is required';
    else if (!validateEmail(formData.email)) newErrors.email = 'Invalid email format';
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  // Handler functions
  const handleNext = useCallback(() => {
    if (currentStep === 1) {
      if (validateStep1()) {
        setCurrentStep(2);
      }
    } else if (currentStep === 2) {
      setCurrentStep(3);
    }
  }, [currentStep]);

  const handleGoBack = useCallback(() => {
    if (currentStep > 1) {
      setCurrentStep((prev) => (prev - 1) as 1 | 2 | 3);
      setErrors({});
    }
  }, [currentStep]);

  const handleComplete = useCallback(() => {
    complete({
      name: formData.name,
      email: formData.email,
      avatar: formData.avatar,
      role: formData.role,
      emailNotifications: formData.emailNotifications,
      theme: formData.theme,
    });
  }, [formData, complete]);

  // Computed: check if Next button should be disabled
  const isStep1Valid = formData.name.trim() && formData.email.trim() && validateEmail(formData.email);
  const isStep2Valid = formData.role.trim();
  const nextDisabled = currentStep === 1 ? !isStep1Valid : false;

  // Progress calculation
  const progressPercent = (currentStep / 3) * 100;

  return (
    <Container maxWidth="2xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)" align="center">
        {/* Header with step indicator and progress bar */}
        <Stack gap="var(--ggui-spacing-4)" align="center" direction="horizontal">
          <Heading level={2}>Setup Your Profile</Heading>
          <Spacer size="flex" />
          <Badge variant="primary" size="md">
            Step {currentStep} of 3
          </Badge>
        </Stack>

        {/* Progress bar */}
        <Box
          background="var(--ggui-color-surfaceVariant)"
          borderRadius="var(--ggui-shape-radius-lg)"
          padding="0"
          style={{ width: '100%', height: '6px', overflow: 'hidden' }}
        >
          <Box
            background="var(--ggui-color-primary-600)"
            borderRadius="var(--ggui-shape-radius-lg)"
            padding="0"
            style={{
              width: `${progressPercent}%`,
              height: '100%',
              transition: 'width 300ms ease-in-out',
            }}
          />
        </Box>

        {/* Step 1: Profile Setup */}
        {currentStep === 1 && (
          <Stack gap="var(--ggui-spacing-6)" align="stretch" style={{ width: '100%', maxWidth: '600px' }}>
            <Stack gap="var(--ggui-spacing-2)">
              <Heading level={3}>Tell Us About Yourself</Heading>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                Let's start with your basic information
              </Text>
            </Stack>

            <Stack gap="var(--ggui-spacing-4)">
              <Input
                label="Full Name"
                placeholder="John Doe"
                value={formData.name}
                onChange={(value) => {
                  setFormData((prev) => ({ ...prev, name: value }));
                  if (errors.name) setErrors((prev) => ({ ...prev, name: '' }));
                }}
                required
                error={errors.name}
              />
              <Input
                label="Email"
                type="email"
                placeholder="you@example.com"
                value={formData.email}
