import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

  const [currentStep, setCurrentStep] = useState<number>(1);
  const [name, setName] = useState<string>('');
  const [email, setEmail] = useState<string>('');
  const [satisfaction, setSatisfaction] = useState<string>('');
  const [selectedFeatures, setSelectedFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState<string>('');
  const [touched, setTouched] = useState<{ name: boolean; email: boolean }>({ name: false, email: false });

  const emailIsValid = useMemo(() => {
    if (!email.trim()) return false;
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim());
  }, [email]);

  const nameError = touched.name && !name.trim() ? 'Name is required.' : '';
  const emailError = touched.email && !email.trim() ? 'Email is required.' : touched.email && !emailIsValid ? 'Please enter a valid email address.' : '';

  const stepOneValid = name.trim().length > 0 && emailIsValid;
  const stepTwoValid = satisfaction !== '';

  const canProceed = useMemo(() => {
    if (currentStep === 1) return stepOneValid;
    if (currentStep === 2) return stepTwoValid;
    if (currentStep === 3) return true;
    if (currentStep === 4) return true;
    return true;
  }, [currentStep, stepOneValid, stepTwoValid]);

  const progressValue = (currentStep / 5) * 100;

  const satisfactionOptions = useMemo(() => {
    if (!props.satisfactionLabels || props.satisfactionLabels.length === 0) {
      return [];
    }
    return props.satisfactionLabels.map((label, index) => ({
      value: String(index + 1),
      label,
    }));
  }, [props.satisfactionLabels]);

  const handleFeatureToggle = useCallback((feature: string, checked: boolean) => {
    setSelectedFeatures((prev) => {
      if (checked) {
        if (prev.includes(feature)) return prev;
        return [...prev, feature];
      }
      return prev.filter((item) => item !== feature);
    });
  }, []);

  const handleNext = useCallback(() => {
    if (currentStep === 1) {
      setTouched((prev) => ({ ...prev, name: true, email: true }));
      if (!stepOneValid) return;
    }
    if (currentStep === 2 && !stepTwoValid) return;
    setCurrentStep((prev) => Math.min(prev + 1, 5));
  }, [currentStep, stepOneValid, stepTwoValid]);

  const handleBack = useCallback(() => {
    setCurrentStep((prev) => Math.max(prev - 1, 1));
  }, []);

  const handleSubmit = useCallback(() => {
    submit({
      name: name.trim(),
      email: email.trim(),
      satisfaction: Number(satisfaction),
      features: selectedFeatures,
      comments: comments.trim(),
    });
  }, [submit, name, email, satisfaction, selectedFeatures, comments]);

  return (
    <Box is="form" onSubmit={(event) => { event.preventDefault(); if (currentStep < 5) { handleNext(); } else { handleSubmit(); } }}>
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-6)" shadow="md">
          <Stack gap="var(--ggui-spacing-4)">
            <Row justify="between" align="center">
              <Heading level={3}>Multi-Step Survey</Heading>
              <Badge variant="primary">{`Step ${currentStep} of 5`}</Badge>
            </Row>
            <Progress value={progressValue} max={100} size="md" />

            {currentStep === 1 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Input
                  label="Name"
                  value={name}
                  onChange={setName}
                  required
                  placeholder="Enter your full name"
                  error={nameError}
                  helperText={!nameError ? 'Your name is required.' : ''}
                />
                <Input
                  label="Email"
                  type="email"
                  value={email}
                  onChange={setEmail}
                  required
                  placeholder="you@example.com"
                  error={emailError}
                  helperText={!emailError ? 'We will only use this for survey follow-up.' : ''}
                />
              </Stack>
            )}

            {currentStep === 2 && (
              <Stack gap="var(--ggui-spacing-3)">
                <RadioGroup
                  label="How satisfied are you?"
                  value={satisfaction}
                  onChange={setSatisfaction}
                  options={satisfactionOptions}
                  error={!stepTwoValid ? 'Please select a satisfaction rating before continuing.' : ''}
                />
              </Stack>
            )}

            {currentStep === 3 && (
              <Box is="fieldset" padding="0" margin="0" borderRadius="var(--ggui-shape-radius-md)">
                <Box is="legend">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Feature interests</Text>
                </Box>
                {(props.featureOptions || []).length === 0 ? (
                  <Alert variant="info" title="No features available">
                    There are currently no feature options to select.
                  </Alert>
                ) : (
                  <Stack gap="var(--ggui-spacing-2)">
                    {(props.featureOptions || []).map((feature) => (
                      <Checkbox
                        key={feature}
                        label={feature}
                        checked={selectedFeatures.includes(feature)}
                        onChange={(checked) => handleFeatureToggle(feature, checked)}
                      />
                    ))}
                  </Stack>
                )}
              </Box>
            )}

            {currentStep === 4 && (
              <Stack gap="var(--ggui-spacing-4)">
                <TextArea
                  label="Additional comments (optional)"
                  value={comments}
                  onChange={setComments}
                  placeholder="Share any additional feedback..."
                  maxLength={500}
                  showCount
                  rows={6}
                  helperText="Maximum 500 characters."
                />
              </Stack>
            )}

            {currentStep === 5 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Review Your Answers</Heading>
                <Card padding="var(--ggui-spacing-4)" border shadow="none">
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text><Text is="span" weight="semibold">Name:</Text> {name || '-'}</Text>
                    <Text><Text is="span" weight="semibold">Email:</Text> {email || '-'}</Text>
                    <Text>
                      <Text is="span" weight="semibold">Satisfaction:</Text>{' '}
                      {satisfaction ? props.satisfactionLabels[Number(satisfaction) - 1] || satisfaction : '-'}
                    </Text>
                    <Text>
                      <Text is="span" weight="semibold">Features:</Text>{' '}
                      {selectedFeatures.length > 0 ? selectedFeatures.join(', ') : 'None selected'}
                    </Text>
                    <Text><Text is="span" weight="semibold">Comments:</Text> {comments.trim() || 'No comments provided'}</Text>
                  </Stack>
                </Card>
              </Stack>
            )}

            <Divider margin="var(--ggui-spacing-2)" />
            <Row justify="between" align="center">
              <Button variant="outline" onClick={handleBack} disabled={currentStep === 1}>
                Back
              </Button>
              {currentStep < 5 ? (
                <Button
                  variant="primary"
                  onClick={handleNext}
                  disabled={!canProceed}
                >
                  Next
                </Button>
              ) : (
                <Button variant="primary" onClick={handleSubmit}>
                  Submit Survey
                </Button>
              )}
            </Row>
          </Stack>
        </Card>
      </Stack>
    </Container>
    </Box>

  );
}

