  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board

  const [localTasks, setLocalTasks] = useState<Array<{ id: string; title: string; priority: 'low' | 'medium' | 'high'; assignee: string; column: string; dueDate?: string }>>([]);
  const [newTaskOpenByColumn, setNewTaskOpenByColumn] = useState<Record<string, boolean>>({});
  const [newTaskTitleByColumn, setNewTaskTitleByColumn] = useState<Record<string, string>>({});
  const [newTaskPriorityByColumn, setNewTaskPriorityByColumn] = useState<Record<string, 'low' | 'medium' | 'high'>>({});
  const [editingTaskId, setEditingTaskId] = useState<string>('');
  const [editingTitle, setEditingTitle] = useState<string>('');

  const columns = useMemo(() => {
    if (props.columns && props.columns.length > 0) {
      return props.columns.map((column, index) => ({
        id: column.id || `column-${index + 1}`,
        name: column.name || `Column ${index + 1}`
      }));
    }
    return [
      { id: 'todo', name: 'To Do' },
      { id: 'in-progress', name: 'In Progress' },
      { id: 'done', name: 'Done' }
    ];
  }, [props.columns]);

  useEffect(() => {
    const fallbackFirstColumn = columns[0]?.id || 'todo';
    setLocalTasks((props.tasks || []).map((task, index) => ({
      id: task.id || `task-${index + 1}`,
      title: task.title || 'Untitled task',
      priority: task.priority || 'medium',
      assignee: task.assignee || 'NA',
      column: task.column || fallbackFirstColumn,
      dueDate: task.dueDate
    })));
  }, [props.tasks, columns]);

  useEffect(() => {
    if (!taskChanged.latest || !taskChanged.latest.task) return;
    const incomingTask = taskChanged.latest.task;
    const incomingId = incomingTask.id || '';
    if (!incomingId) return;

    setLocalTasks((prev) => {
      if (taskChanged.latest?.action === 'delete') {
        return prev.filter((task) => task.id !== incomingId);
      }

      const mappedTask = {
        id: incomingId,
        title: incomingTask.title || 'Untitled task',
        priority: incomingTask.priority || 'medium',
        assignee: incomingTask.assignee || 'NA',
        column: incomingTask.column || (columns[0]?.id || 'todo'),
        dueDate: incomingTask.dueDate
      } as { id: string; title: string; priority: 'low' | 'medium' | 'high'; assignee: string; column: string; dueDate?: string };

      const existingIndex = prev.findIndex((task) => task.id === incomingId);
      if (existingIndex === -1) return [...prev, mappedTask];
      return prev.map((task) => (task.id === incomingId ? { ...task, ...mappedTask } : task));
    });
  }, [taskChanged.latest, columns]);

  const tasksByColumn = useMemo(() => {
    const grouped: Record<string, Array<{ id: string; title: string; priority: 'low' | 'medium' | 'high'; assignee: string; column: string; dueDate?: string }>> = {};
    columns.forEach((column) => {
      grouped[column.id] = [];
    });
    localTasks.forEach((task) => {
      if (!grouped[task.column]) grouped[task.column] = [];
      grouped[task.column].push(task);
    });
    return grouped;
  }, [localTasks, columns]);

  const totalTasks = localTasks.length;
  const doneColumnId = useMemo(() => {
    const explicitDone = columns.find((column) => (column.name || '').toLowerCase() === 'done');
    return explicitDone?.id || 'done';
  }, [columns]);
  const completedCount = useMemo(
    () => localTasks.filter((task) => task.column === doneColumnId).length,
    [localTasks, doneColumnId]
  );

  const priorityVariant = useCallback((priority: 'low' | 'medium' | 'high') => {
    if (priority === 'high') return 'error';
    if (priority === 'medium') return 'warning';
    return 'success';
  }, []);

  const moveTask = useCallback((taskId: string, nextColumn: string) => {
    setLocalTasks((prev) => prev.map((task) => (task.id === taskId ? { ...task, column: nextColumn } : task)));
    taskUpdate({ action: 'move', taskId, data: { column: nextColumn } });
  }, [taskUpdate]);

  const startEdit = useCallback((taskId: string, currentTitle: string) => {
    setEditingTaskId(taskId);
    setEditingTitle(currentTitle);
  }, []);

  const saveEdit = useCallback((taskId: string) => {
    const trimmed = editingTitle.trim();
    if (!trimmed) return;
    const existingTask = localTasks.find((task) => task.id === taskId);
    const nextColumn = existingTask?.column || (columns[0]?.id || 'todo');
    setLocalTasks((prev) => prev.map((task) => (task.id === taskId ? { ...task, title: trimmed } : task)));
    taskUpdate({ action: 'edit', taskId, data: { column: nextColumn, title: trimmed, priority: existingTask?.priority || 'medium' } as unknown as { column: string } });
    setEditingTaskId('');
    setEditingTitle('');
  }, [editingTitle, taskUpdate, localTasks, columns]);

  const cancelEdit = useCallback(() => {
    setEditingTaskId('');
    setEditingTitle('');
  }, []);


  const openAddTask = useCallback((columnId: string) => {
    setNewTaskOpenByColumn((prev) => ({ ...prev, [columnId]: true }));
    setNewTaskPriorityByColumn((prev) => ({ ...prev, [columnId]: prev[columnId] || 'medium' }));
    setNewTaskTitleByColumn((prev) => ({ ...prev, [columnId]: prev[columnId] || '' }));
  }, []);

  const createTask = useCallback((columnId: string) => {
    const title = (newTaskTitleByColumn[columnId] || '').trim();
    if (!title) return;
    const createdId = `task-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
    const todoColumn = columns.find((c) => (c.id || '').toLowerCase() === 'todo' || (c.name || '').toLowerCase() === 'to do')?.id || 'todo';
    const createdTask = {
      id: createdId,
      title,
      priority: newTaskPriorityByColumn[columnId] || 'medium',
      assignee: 'NA',
      column: todoColumn
    } as { id: string; title: string; priority: 'low' | 'medium' | 'high'; assignee: string; column: string; dueDate?: string };

    setLocalTasks((prev) => [...prev, createdTask]);
    taskUpdate({ action: 'create', taskId: createdId, data: { column: createdTask.column, title: createdTask.title, priority: createdTask.priority } as unknown as { column: string } });
    setNewTaskOpenByColumn((prev) => ({ ...prev, [columnId]: false }));
    setNewTaskTitleByColumn((prev) => ({ ...prev, [columnId]: '' }));
    setNewTaskPriorityByColumn((prev) => ({ ...prev, [columnId]: 'medium' }));
  }, [newTaskTitleByColumn, newTaskPriorityByColumn, columns, taskUpdate]);

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-4)" shadow="sm" border radius="lg">
          <Row justify="between" align="center" wrap>
            <Heading level={2}>Task Board</Heading>
            <Row gap="var(--ggui-spacing-3)" align="center" wrap>
              <Badge variant="primary">Total: {totalTasks}</Badge>
              <Badge variant="success">Completed: {completedCount}</Badge>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                Live updates: {taskChanged.all.length}
              </Text>
            </Row>
          </Row>
        </Card>

        {localTasks.length === 0 ? (
          <Alert variant="info" title="No tasks yet">
            Add a task to get started.
          </Alert>
        ) : null}

        <Row gap="var(--ggui-spacing-4)" wrap align="start">
          {columns.map((column) => (
            <Card key={column.id} padding="var(--ggui-spacing-4)" shadow="sm" border radius="lg">
              <Stack gap="var(--ggui-spacing-3)">
                <Row justify="between" align="center">
                  <Heading level={3}>{column.name}</Heading>
                  <Badge variant="default">{(tasksByColumn[column.id] || []).length}</Badge>
                </Row>

                <Stack gap="var(--ggui-spacing-3)">
                  {(tasksByColumn[column.id] || []).map((task) => (
                    <Card key={task.id} padding="var(--ggui-spacing-3)" shadow="none" border radius="md">
                      <Stack gap="var(--ggui-spacing-2)">
                        {editingTaskId === task.id ? (
                          <Row gap="var(--ggui-spacing-2)" align="end">
                            <Input label="Edit task title" value={editingTitle} onChange={setEditingTitle} placeholder="Task title" />
                            <Button variant="primary" size="sm" onPress={() => saveEdit(task.id)}>Save</Button>
                            <Button variant="ghost" size="sm" onPress={cancelEdit}>Cancel</Button>
                          </Row>
                        ) : (
                          <Row justify="between" align="center">
                            <Text as={Clickable} onClick={() => startEdit(task.id, task.title)} weight="medium">{task.title}</Text>
                            <Button variant="ghost" size="sm" onPress={() => startEdit(task.id, task.title)}>Edit</Button>
                          </Row>
                        )}
                        <Row gap="var(--ggui-spacing-2)" align="center" wrap>
                          <Badge variant={priorityVariant(task.priority)}>{task.priority}</Badge>
                          <Avatar name={task.assignee} size="sm" />
                          {task.dueDate ? (
                            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Due {task.dueDate}</Text>
                          ) : (
                            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">No due date</Text>
                          )}
                        </Row>

                        <Select
                          label="Move task"
                          value={task.column}
                          onChange={(value) => moveTask(task.id, value)}
                          options={columns.map((c) => ({ value: c.id, label: c.name }))}
                        />
                      </Stack>
                    </Card>
                  ))}
                </Stack>

                {newTaskOpenByColumn[column.id] ? (
                  <Card padding="var(--ggui-spacing-3)" shadow="none" border radius="md">
                    <Stack gap="var(--ggui-spacing-2)">
                      <Input
                        label="Task title"
                        value={newTaskTitleByColumn[column.id] || ''}
                        onChange={(value) => setNewTaskTitleByColumn((prev) => ({ ...prev, [column.id]: value }))}
                        placeholder="Enter task title"
                      />
                      <Select
                        label="Priority"
                        value={newTaskPriorityByColumn[column.id] || 'medium'}
                        onChange={(value) => setNewTaskPriorityByColumn((prev) => ({ ...prev, [column.id]: (value as 'low' | 'medium' | 'high') }))}
                        options={[
                          { value: 'low', label: 'Low' },
                          { value: 'medium', label: 'Medium' },
                          { value: 'high', label: 'High' }
                        ]}
                      />
                      <Row gap="var(--ggui-spacing-2)">
                        <Button variant="primary" size="sm" onPress={() => createTask(column.id)}>Create</Button>
                        <Button
                          variant="ghost"
                          size="sm"
                          onPress={() => setNewTaskOpenByColumn((prev) => ({ ...prev, [column.id]: false }))}
                        >
                          Cancel
                        </Button>
                      </Row>
                    </Stack>
                  </Card>
                ) : null}

                <Button variant="ghost" size="sm" onPress={() => openAddTask(column.id)}>+ Add Task</Button>
              </Stack>
            </Card>
          ))}
        </Row>
      </Stack>
    </Container>

  );
}

