}





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  const [searchValue, setSearchValue] = useState<string>('');
  const [selectedAtomicNumber, setSelectedAtomicNumber] = useState<number | null>(null);

  const categoryColorMap = useMemo(() => ({
    'alkali metal': 'var(--ggui-color-error-100)',
    'alkaline earth metal': 'var(--ggui-color-warning-100)',
    'transition metal': 'var(--ggui-color-primary-100)',
    'post-transition metal': 'var(--ggui-color-primary-200)',
    metalloid: 'var(--ggui-color-info-100)',
    nonmetal: 'var(--ggui-color-success-100)',
    halogen: 'var(--ggui-color-warning-200)',
    'noble gas': 'var(--ggui-color-primary-300)',
    'noble-gas': 'var(--ggui-color-primary-300)',
    lanthanide: 'var(--ggui-color-success-200)',
    actinide: 'var(--ggui-color-error-200)',
    unknown: 'var(--ggui-color-surfaceVariant)',
  }), []);

  const normalizedElements = useMemo(() => {
    return (props.elements || []).map((element) => ({
      atomicNumber: element.atomicNumber ?? 0,
      symbol: element.symbol ?? '',
      name: element.name ?? '',
      atomicWeight: element.atomicWeight ?? 0,
      category: element.category ?? 'unknown',
      row: element.row ?? 1,
      col: element.col ?? 1,
    }));
  }, [props.elements]);

  const filteredElements = useMemo(() => {
    const term = searchValue.trim().toLowerCase();
    if (!term) {
      return normalizedElements;
    }
    return normalizedElements.filter((element) =>
      element.name.toLowerCase().includes(term) || element.symbol.toLowerCase().includes(term)
    );
  }, [normalizedElements, searchValue]);

  const selectedElement = useMemo(() => {
    if (selectedAtomicNumber === null) {
      return null;
    }
    return normalizedElements.find((element) => element.atomicNumber === selectedAtomicNumber) ?? null;
  }, [normalizedElements, selectedAtomicNumber]);

  useEffect(() => {
    if (filteredElements.length === 0) {
      setSelectedAtomicNumber(null);
      return;
    }
    if (selectedAtomicNumber === null) {
      return;
    }
    const stillVisible = filteredElements.some((element) => element.atomicNumber === selectedAtomicNumber);
    if (!stillVisible) {
      setSelectedAtomicNumber(null);
    }
  }, [filteredElements, selectedAtomicNumber]);

  const categories = useMemo(() => {
    const unique = new Set<string>();
    normalizedElements.forEach((element) => unique.add(element.category || 'unknown'));
    return Array.from(unique.values());
  }, [normalizedElements]);

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-4)">
        <Heading level={2}>Interactive Periodic Table</Heading>
        <Input
          label="Search elements"
          placeholder="Type element name or symbol"
          value={searchValue}
          onChange={setSearchValue}
        />

        {normalizedElements.length === 0 ? (
          <Alert variant="warning" title="No element data">
            No periodic table data is available.
          </Alert>
        ) : (
          <Card padding="var(--ggui-spacing-4)" border radius="lg" shadow="sm">
            <Box
              style={{
                display: 'grid',
                gridTemplateColumns: 'repeat(18, minmax(44px, 1fr))',
                gap: 'var(--ggui-spacing-2)',
                overflowX: 'auto',
              }}
            >

              {filteredElements.map((element) => {
                const isSelected = selectedAtomicNumber === element.atomicNumber;
                const background = categoryColorMap[element.category as keyof typeof categoryColorMap] || 'var(--ggui-color-surfaceVariant)';
                return (
                  <Card
                    key={element.atomicNumber}
                    as={Clickable}
                    onClick={() => setSelectedAtomicNumber(element.atomicNumber)}
                    onKeyDown={(event: React.KeyboardEvent) => {
                      if (event.key === 'Enter' || event.key === ' ') {
                        event.preventDefault();
                        setSelectedAtomicNumber(element.atomicNumber);
                      }
                    }}
                    aria-label={`${element.name}, atomic number ${element.atomicNumber}` }
                    padding="var(--ggui-spacing-2)"
                    border
                    radius="md"
                    shadow={isSelected ? 'md' : 'none'}
                    hoverStyle={{
                      boxShadow: 'var(--ggui-shape-shadow-sm)',
                      outline: '1px solid var(--ggui-color-primary-400)',
                    }}
                    style={{
                      gridColumn: element.col,
                      gridRow: element.row,
                      background,
                      minHeight: '64px',
                      position: 'relative',
                      cursor: 'pointer',
                      outline: isSelected ? '2px solid var(--ggui-color-primary-600)' : 'none',
                      outlineOffset: '2px',
                    }}
                  >
                    <Text
                      variant="caption"
                      color="var(--ggui-color-onSurfaceVariant)"
                      style={{ position: 'absolute', top: 'var(--ggui-spacing-1)', left: 'var(--ggui-spacing-1)' }}
                    >
                      {element.atomicNumber}
                    </Text>
                    <Text
                      weight="bold"
                      size="lg"
                      align="center"
                      style={{ marginTop: 'var(--ggui-spacing-3)' }}
                    >
                      {element.symbol}
                    </Text>
                  </Card>
                );
              })}
            </Box>
          </Card>
        )}

        {filteredElements.length === 0 && normalizedElements.length > 0 && (
          <Alert variant="info" title="No matches">
            No elements matched your search. Try a different name or symbol.
          </Alert>
        )}

        <Card padding="var(--ggui-spacing-4)" border radius="lg">
          <Stack gap="var(--ggui-spacing-2)">
            <Heading level={3}>Element Details</Heading>
            {selectedElement ? (
              <Stack gap="var(--ggui-spacing-1)">
                <Text><Text is="span" weight="semibold">Name:</Text> {selectedElement.name}</Text>
                <Text><Text is="span" weight="semibold">Symbol:</Text> {selectedElement.symbol}</Text>
                <Text><Text is="span" weight="semibold">Atomic Number:</Text> {selectedElement.atomicNumber}</Text>
                <Text><Text is="span" weight="semibold">Atomic Weight:</Text> {selectedElement.atomicWeight}</Text>
                <Text><Text is="span" weight="semibold">Category:</Text> {selectedElement.category}</Text>
              </Stack>
            ) : (
              <Text color="var(--ggui-color-onSurfaceVariant)">Select an element to view details.</Text>
            )}
          </Stack>
        </Card>

        <Card padding="var(--ggui-spacing-4)" border radius="lg">
          <Stack gap="var(--ggui-spacing-3)">
            <Heading level={3}>Legend</Heading>
            <Box
              style={{
                display: 'grid',
                gridTemplateColumns: 'repeat(auto-fill, minmax(180px, 1fr))',
                gap: 'var(--ggui-spacing-2)',
              }}
            >
              {categories.map((category) => (
                <Row key={category} gap="var(--ggui-spacing-2)" align="center">
                  <Box
                    style={{
                      width: '16px',
                      height: '16px',
                      borderRadius: 'var(--ggui-shape-radius-sm)',
                      border: '1px solid var(--ggui-color-outline)',
                      background: categoryColorMap[category as keyof typeof categoryColorMap] || 'var(--ggui-color-surfaceVariant)',
                    }}
                  />
                  <Text variant="bodySmall">{category}</Text>
                </Row>
              ))}
            </Box>

          </Stack>
        </Card>
      </Stack>
    </Container>

  );
}

