                                name={index < review.rating ? 'star' : 'star-off'}
                                size={14}
                                color={index < review.rating ? 'var(--ggui-color-warning-500)' : 'var(--ggui-color-outline)'}
                              />
                            ))}
                          </Row>
                          <Text color="var(--ggui-color-onSurfaceVariant)">{review.text}</Text>
                        </Stack>
                      </Card>
                    ))}
                  </Stack>
                ) : (
                  <Alert variant="info">No reviews yet.</Alert>
                ),
              },
            ]}
          />
        </Card>

        <Card padding="var(--ggui-spacing-6)">
          <Stack gap="var(--ggui-spacing-4)">
            <Heading level={4}>Purchase</Heading>
            <Row gap="var(--ggui-spacing-2)" align="center" wrap>
              <Button variant="outline" onPress={decrementQuantity} disabled={quantity <= 1}>
                -
              </Button>
              <Input
                label="Quantity"
                value={String(quantity)}
                onChange={(value) => {
                  const parsed = Number(value);
                  if (Number.isNaN(parsed)) {
                    return;
                  }
                  if (maxStock <= 0) {
                    setQuantity(1);
                    return;
                  }
                  setQuantity(Math.min(Math.max(1, Math.round(parsed)), maxStock));
                }}
                type="number"
              />
              <Button variant="outline" onPress={incrementQuantity} disabled={maxStock <= 0 || quantity >= maxStock}>
                +
              </Button>
            </Row>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
              Available stock: {String(maxStock)}
            </Text>
            <Button
              variant="primary"
              disabled={maxStock <= 0 || !props.product?.id}
              onPress={handleAddToCart}
            >
              Add to Cart
            </Button>
          </Stack>
        </Card>
      </Stack>
    </Container>

  );
}

