            <Row gap="var(--ggui-spacing-2)" align="center">
              <Badge variant="primary">{props.participantCount} participants</Badge>
              {typingState?.active && typingState?.sender && typingState.sender !== props.currentUser ? (
                <Badge variant="info">{typingState.sender} is typing...</Badge>
              ) : null}
            </Row>
          </Row>

          <Divider margin="var(--ggui-spacing-2)" color="var(--ggui-color-outlineVariant)" />

          <Box
            padding="var(--ggui-spacing-3)"
            background="var(--ggui-color-surface)"
            borderRadius="var(--ggui-shape-radius-md)"
          >
            <Stack
              gap="var(--ggui-spacing-3)"
              >
              <Box>
                <div
                  ref={scrollRef}
                  style={{
                    maxHeight: '55vh',
                    overflowY: 'auto',
                    padding: 'var(--ggui-spacing-2)',
                  }}
                >
                  <Stack gap="var(--ggui-spacing-3)">
                    {groupedMessages.length === 0 ? (
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">No messages yet</Text>
                    ) : (
                      groupedMessages.map((group, groupIndex) => {
                        const isOwnGroup = group.sender === props.currentUser;
                        return (
                          <Stack key={`${group.sender || 'unknown'}-${groupIndex}`} align={isOwnGroup ? 'end' : 'start'} gap="var(--ggui-spacing-1)">
                            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{group.sender || 'Unknown sender'}</Text>
                            {(group.items || []).map((item, itemIndex) => (
                              <Box
                                key={`${groupIndex}-${itemIndex}-${item.timestamp || item.text || 'msg'}`}
                                padding="var(--ggui-spacing-3)"
                                background={isOwnGroup ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-surfaceVariant)'}
                                borderRadius="var(--ggui-shape-radius-md)"
                              >
                                <Stack gap="var(--ggui-spacing-1)">
                                  <Text color={isOwnGroup ? 'var(--ggui-color-onContainer)' : 'var(--ggui-color-onSurface)'}>{item.text || ''}</Text>
                                  <Text variant="caption" color={isOwnGroup ? 'var(--ggui-color-onContainer)' : 'var(--ggui-color-onSurfaceVariant)'}>
                                    {formatTimestamp(item.timestamp)}
                                  </Text>
                                </Stack>
                              </Box>
                            ))}
                          </Stack>
                        );
                      })
                    )}
                  </Stack>
                </div>
              </Box>
            </Stack>
          </Box>

          <Divider margin="var(--ggui-spacing-2)" color="var(--ggui-color-outlineVariant)" />

          <Row gap="var(--ggui-spacing-2)" align="end">
            <Box padding="0" style={{ flex: 1 } as React.CSSProperties}>
              <Input
                label="Message"
                placeholder="Type your message"
                value={draft}
                onChange={setDraft}
                onKeyDown={(e) => {
                  if (e.key === 'Enter') {
                    e.preventDefault();
                    handleSend();
                  }
                }}
              />
            </Box>
            <Button variant="primary" onClick={handleSend} disabled={!draft.trim()}>
              Send
            </Button>
          </Row>
        </Stack>
      </Card>
    </Container>

  );
}

