import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>; // Array of stocks with symbol, name, price, change, changePercent
}


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };




export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update
  const [stockData, setStockData] = useState<Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>>(props.stocks || []);
  const [lastUpdated, setLastUpdated] = useState<Date>(new Date());
  const [now, setNow] = useState<Date>(new Date());
  const [flashMap, setFlashMap] = useState<Record<string, number>>({});

  useEffect(() => {
    setStockData(props.stocks || []);
  }, [props.stocks]);

  useEffect(() => {
    const timer = setInterval(() => {
      setNow(new Date());
    }, 1000);
    return () => clearInterval(timer);
  }, []);

  useEffect(() => {
    if (!priceUpdate.latest || !priceUpdate.latest.symbol) return;
    const updatedSymbol = priceUpdate.latest.symbol;
    setStockData((prev) => {
      const next = (prev || []).map((stock) => {
        if (stock.symbol === updatedSymbol) {
          return {
            ...stock,
            price: priceUpdate.latest?.price ?? stock.price,
            change: priceUpdate.latest?.change ?? stock.change,
            changePercent: priceUpdate.latest?.changePercent ?? stock.changePercent,
          };
        }
        return stock;
      });
      const exists = (next || []).some((stock) => stock.symbol === updatedSymbol);
      if (!exists) {
        next.push({
          symbol: updatedSymbol,
          name: updatedSymbol,
          price: priceUpdate.latest?.price,
          change: priceUpdate.latest?.change,
          changePercent: priceUpdate.latest?.changePercent,
        });
      }
      return next;
    });
    setLastUpdated(new Date());
    setFlashMap((prev) => ({ ...prev, [updatedSymbol]: Date.now() }));
  }, [priceUpdate.latest]);

  useEffect(() => {
    if (!priceUpdate.latest || !priceUpdate.latest.symbol) return;
    const symbol = priceUpdate.latest.symbol;
    const timeout = setTimeout(() => {
      setFlashMap((prev) => {
        const next = { ...prev };
        delete next[symbol];
        return next;
      });
    }, 900);
    return () => clearTimeout(timeout);
  }, [priceUpdate.latest]);

  const marketStatusLabel = useMemo(() => {
    return marketStatus.latest?.status || 'open';
  }, [marketStatus.latest]);

  const marketStatusTime = useMemo(() => {
    if (!marketStatus.latest?.timestamp) return null;
    const parsed = new Date(marketStatus.latest.timestamp);
    if (Number.isNaN(parsed.getTime())) return null;
    return parsed.toLocaleTimeString();
  }, [marketStatus.latest]);

  const formatCurrency = useCallback((value?: number) => {
    const safeValue = value ?? 0;
    return `$${safeValue.toFixed(2)}`;
  }, []);

  const formatSigned = useCallback((value?: number) => {
    const safeValue = value ?? 0;
    const abs = Math.abs(safeValue).toFixed(2);
    return `${safeValue >= 0 ? '+' : '-'}$${abs}`;
  }, []);

  const formatPercent = useCallback((value?: number) => {
    const safeValue = value ?? 0;
    const abs = Math.abs(safeValue).toFixed(2);
    return `${safeValue >= 0 ? '+' : '-'}${abs}%`;
  }, []);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card
          padding="var(--ggui-spacing-5)"
          border
          radius="lg"
          style={{ background: 'var(--ggui-color-surfaceVariant)', borderColor: 'var(--ggui-color-outline)' }}
        >
          <Row justify="between" align="center" wrap>
            <Stack gap="var(--ggui-spacing-1)">
              <Heading level={1} color="var(--ggui-color-onSurface)">Market Watch</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                Last Updated: {lastUpdated.toLocaleTimeString()} (live clock: {now.toLocaleTimeString()})
              </Text>
            </Stack>
            <Stack gap="var(--ggui-spacing-1)" align="end">
              <Badge
                variant={marketStatusLabel === 'open' ? 'success' : marketStatusLabel === 'closed' ? 'error' : 'warning'}
              >
                {marketStatusLabel}
              </Badge>
              {marketStatusTime && (
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                  Status updated: {marketStatusTime}
                </Text>
              )}
            </Stack>
          </Row>
        </Card>

        {(!stockData || stockData.length === 0) && (
          <Alert variant="info" title="No stocks available">
            There are currently no stock entries to display.
          </Alert>
        )}

        {stockData && stockData.length > 0 && (
          <CardGrid columns={{ sm: 1, md: 2, lg: 3 }} gap={16}>
            {stockData.map((stock, index) => {
              const symbol = stock.symbol || `STK-${index}`;
              const changeValue = stock.change ?? 0;
              const isPositive = changeValue >= 0;
              const isFlashing = !!flashMap[symbol];
              const trendColor = isPositive ? 'var(--ggui-color-success-600)' : 'var(--ggui-color-error-600)';

              return (
                <Card
                  key={`${symbol}-${flashMap[symbol] || 'base'}` }
                  padding="var(--ggui-spacing-4)"
                  shadow="sm"
                  border
                  radius="lg"
                  style={{
                    borderColor: trendColor,
                    background: 'var(--ggui-color-surface)',
                    animation: isFlashing ? 'ggui-flash 700ms ease-out' : 'none',
                    transition: 'border-color 200ms ease-in-out, transform 200ms ease-in-out',
                  }}
                >
                  <Stack gap="var(--ggui-spacing-2)">
                    <Heading level={3} color="var(--ggui-color-onSurface)">{symbol}</Heading>
                    <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                      {stock.name || 'Unknown Company'}
                    </Text>
                    <Text variant="bodyLarge" weight="bold" color="var(--ggui-color-onSurface)">
                      {formatCurrency(stock.price)}
                    </Text>
                    <Row justify="between" align="center">
                      <Text variant="label" color={trendColor}>
                        {formatSigned(stock.change)}
                      </Text>
                      <Row align="center" gap="var(--ggui-spacing-1)">
                        <Text variant="label" color={trendColor}>
                          {isPositive ? '▲' : '▼'} {formatPercent(stock.changePercent)}
                        </Text>
                      </Row>
                    </Row>
                  </Stack>
                </Card>
              );
            })}
          </CardGrid>
        )}

        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
          Stream updates received: {priceUpdate.all.length}
        </Text>
      </Stack>
    </Container>
  );
}

