  const [avatar, setAvatar] = useState(props.initialProfile?.avatar || avatars[0] || '😀');
  const [role, setRole] = useState(props.initialProfile?.role || '');
  const [emailNotifications, setEmailNotifications] = useState(props.initialProfile?.emailNotifications ?? true);
  const [theme, setTheme] = useState((props.initialProfile?.theme || 'light').toLowerCase() === 'dark' ? 'dark' : 'light');
  const [showErrors, setShowErrors] = useState(false);

  useEffect(() => {
    if (!avatars.includes(avatar)) {
      setAvatar(avatars[0] || '😀');
    }
  }, [avatars, avatar]);

  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  const emailError = useMemo(() => {
    if (!showErrors && email.length === 0) {
      return '';
    }
    if (email.trim().length === 0) {
      return 'Email is required';
    }
    if (!emailRegex.test(email.trim())) {
      return 'Please enter a valid email address';
    }
    return '';
  }, [email, showErrors]);

  const nameError = useMemo(() => {
    if (!showErrors && name.length === 0) {
      return '';
    }
    if (name.trim().length === 0) {
      return 'Name is required';
    }
    return '';
  }, [name, showErrors]);

  const isStep1Valid = name.trim().length > 0 && emailRegex.test(email.trim()) && avatar.trim().length > 0;
  const isStep2Valid = role.trim().length > 0 && (theme === 'light' || theme === 'dark');
  const isCurrentStepValid = step === 1 ? isStep1Valid : step === 2 ? isStep2Valid : true;
  const progressValue = (step / 3) * 100;

  const handleNext = useCallback(() => {
    if (step === 1 && !isStep1Valid) {
      setShowErrors(true);
      return;
    }
    if (step === 2 && !isStep2Valid) {
      return;
    }
    setShowErrors(false);
    setStep((prev) => (prev < 3 ? prev + 1 : prev));
  }, [step, isStep1Valid, isStep2Valid]);

  const handleBack = useCallback(() => {
    setStep((prev) => (prev > 1 ? prev - 1 : prev));
  }, []);

  const handleComplete = useCallback(() => {
    if (!isStep1Valid || !isStep2Valid) {
      return;
    }
    complete({
      name: name.trim(),
      email: email.trim(),
      avatar,
      role,
      emailNotifications,
      theme,
    });
  }, [complete, name, email, avatar, role, emailNotifications, theme, isStep1Valid, isStep2Valid]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-6)" shadow="sm" border radius="lg">
          <Stack gap="var(--ggui-spacing-4)">
            <Row justify="between" align="center">
              <Heading level={3}>Onboarding Setup</Heading>
              <Badge variant="primary">Step {step} of 3</Badge>
            </Row>
            <Progress value={progressValue} max={100} size="md" showLabel />
            <Row gap="var(--ggui-spacing-2)">
              <Badge variant={step >= 1 ? 'primary' : 'default'}>1. Profile</Badge>
              <Badge variant={step >= 2 ? 'primary' : 'default'}>2. Preferences</Badge>
              <Badge variant={step >= 3 ? 'primary' : 'default'}>3. Review</Badge>
            </Row>
          </Stack>
        </Card>

        <Card
          padding="var(--ggui-spacing-6)"
          shadow="sm"
          border
          radius="lg"
        >
          <Box
            style={{
              animation: 'ggui-fadeIn 200ms ease-out',
            }}
          >
            {step === 1 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Profile Setup</Heading>
                <Input
                  label="Name"
                  value={name}
                  onChange={setName}
                  placeholder="Enter your full name"
                  required
                  error={nameError || undefined}
                />
                <Input
                  label="Email"
                  type="email"
                  value={email}
                  onChange={setEmail}
                  placeholder="you@example.com"
                  required
                  error={emailError || undefined}
                />
                <Stack gap="var(--ggui-spacing-2)">
                  <Text variant="label">Choose an avatar</Text>
                  <Row gap="var(--ggui-spacing-2)" wrap>
                    {avatars.map((option) => (
                      <Card
                        key={option}
                        as={Clickable}
                        onClick={() => setAvatar(option)}
                        padding="var(--ggui-spacing-3)"
                        border
                        radius="md"
                        shadow="none"
                        hoverStyle={{ opacity: 0.9 }}
                        style={{
                          borderColor: avatar === option ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-outline)',
                          background: avatar === option ? 'var(--ggui-color-primary-50)' : 'var(--ggui-color-surface)',
                        }}
                      >
                        <Text size="2xl" align="center">{option}</Text>
                      </Card>
                    ))}
                  </Row>
                </Stack>
              </Stack>
            )}

            {step === 2 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Preferences</Heading>
                <Select
                  label="Role"
                  value={role}
                  onChange={setRole}
                  placeholder="Select your role"
                  options={roles.map((item) => ({ value: item, label: item }))}
                  required
                />
                <Toggle
                  label="Enable email notifications"
                  checked={emailNotifications}
                  onChange={setEmailNotifications}
                />
                <Toggle
                  label="Dark theme"
                  checked={theme === 'dark'}
                  onChange={(checked) => setTheme(checked ? 'dark' : 'light')}
                />
              </Stack>
            )}

            {step === 3 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Review & Confirm</Heading>
                <Card padding="var(--ggui-spacing-4)" shadow="none" border radius="md">
                  <Stack gap="var(--ggui-spacing-2)">
                    <Row justify="between"><Text variant="label">Name</Text><Text>{name || '—'}</Text></Row>
                    <Row justify="between"><Text variant="label">Email</Text><Text>{email || '—'}</Text></Row>
                    <Row justify="between"><Text variant="label">Avatar</Text><Text>{avatar || '—'}</Text></Row>
                    <Row justify="between"><Text variant="label">Role</Text><Text>{role || '—'}</Text></Row>
                    <Row justify="between"><Text variant="label">Email Notifications</Text><Text>{emailNotifications ? 'On' : 'Off'}</Text></Row>
                    <Row justify="between"><Text variant="label">Theme</Text><Text>{theme}</Text></Row>
                  </Stack>
                </Card>
                <Alert variant="info" title="Ready to complete?">
                  Review your information and complete setup.
                </Alert>
              </Stack>
            )}
          </Box>
        </Card>

        <Row justify="between" align="center">
          <Button variant="outline" onClick={handleBack} disabled={step === 1}>
            Back
          </Button>
          <Row gap="var(--ggui-spacing-2)">
            {step < 3 && (
              <Button variant="primary" onClick={handleNext} disabled={!isCurrentStepValid && step !== 1}>
                Next
              </Button>
            )}
            {step === 3 && (
              <>
                <Button variant="outline" onClick={() => setStep(2)}>
                  Go Back
                </Button>
                <Button variant="primary" onClick={handleComplete} disabled={!isStep1Valid || !isStep2Valid}>
                  Complete Setup
                </Button>
              </>
            )}
          </Row>
        </Row>
      </Stack>
    </Container>

  );
}
